import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

/**
 * Orbital ring system — each photo orbits the heart like a planet.
 * Rings are spread far apart so photos never overlap when zoomed out.
 */

const RINGS = [
  // { count, radius, tiltX, tiltZ, speed, ySpread }
  { count: 8,  radius: 6.5,  tiltX: 0.0,  tiltZ: 0.0,  speed: 0.28, ySpread: 0.3  },
  { count: 10, radius: 9.0,  tiltX: 0.5,  tiltZ: 0.2,  speed: 0.20, ySpread: 0.5  },
  { count: 12, radius: 12.0, tiltX: -0.4, tiltZ: 0.35, speed: 0.14, ySpread: 0.4  },
  { count: 10, radius: 15.0, tiltX: 0.7,  tiltZ: -0.3, speed: 0.10, ySpread: 0.6  },
  { count: 10, radius: 18.5, tiltX: -0.6, tiltZ: 0.5,  speed: 0.07, ySpread: 0.5  },
];

/**
 * Build a list of orbit params for each photo index.
 * Returns: { ringIndex, orbitAngleOffset, radius, tiltX, tiltZ, speed, floatOffset }
 */
function buildOrbitParams(count) {
  const params = [];
  let idx = 0;
  for (let r = 0; r < RINGS.length && idx < count; r++) {
    const ring = RINGS[r];
    const actualCount = Math.min(ring.count, count - idx);
    for (let i = 0; i < actualCount; i++) {
      params.push({
        ringIndex: r,
        orbitAngleOffset: (i / ring.count) * Math.PI * 2,
        radius: ring.radius,
        tiltX: ring.tiltX,
        tiltZ: ring.tiltZ,
        speed: ring.speed,
        floatOffset: idx * 0.61,
        ySpread: ring.ySpread,
      });
      idx++;
    }
  }
  // Remaining overflow — add to outermost ring with bigger radius
  while (idx < count) {
    params.push({
      ringIndex: 5,
      orbitAngleOffset: ((idx % 8) / 8) * Math.PI * 2,
      radius: 22.0 + Math.random() * 3,
      tiltX: (Math.random() - 0.5) * 1.2,
      tiltZ: (Math.random() - 0.5) * 0.8,
      speed: 0.05,
      floatOffset: idx * 0.61,
      ySpread: 0.6,
    });
    idx++;
  }
  return params;
}

// Shared orbital animation hook
function useOrbitalPosition(orbit, meshRef, materialRef) {
  useFrame((state) => {
    if (!meshRef.current) return;
    const t = state.clock.elapsedTime;

    // Current orbital angle
    const angle = orbit.orbitAngleOffset + t * orbit.speed;

    // Position on tilted elliptical ring
    const x = Math.cos(angle) * orbit.radius;
    const z = Math.sin(angle) * orbit.radius;

    // Apply ring tilt via rotation matrix math
    const cosX = Math.cos(orbit.tiltX);
    const sinX = Math.sin(orbit.tiltX);
    const cosZ = Math.cos(orbit.tiltZ);
    const sinZ = Math.sin(orbit.tiltZ);

    meshRef.current.position.x = x * cosZ - z * sinZ;
    meshRef.current.position.y = (x * sinZ + z * cosZ) * sinX
      + Math.sin(t * 0.5 + orbit.floatOffset) * orbit.ySpread;
    meshRef.current.position.z = (x * sinZ + z * cosZ) * cosX;

    // Always face the center (billboard-like but keep slight tilt)
    meshRef.current.rotation.y = -angle + Math.PI * 0.5;
    meshRef.current.rotation.x = Math.sin(t * 0.3 + orbit.floatOffset) * 0.08;

    // Fade effect: when photo passes "behind" (sin of angle near -1),
    // smoothly fade out and back in — creates a disappear-reappear effect every ~2 orbits
    if (materialRef && materialRef.current) {
      // fadePhase: 0 = fully visible, fade out at back, reappear at front
      const fadePhase = Math.sin(angle * 0.5); // half speed → visible every 2 full rotations
      // When fadePhase goes below -0.6, start fading
      const opacity = fadePhase < -0.6
        ? Math.max(0, (fadePhase + 0.6) / (-0.4) * -1 + 1)  // 0 → 1 fade
        : 1.0;
      materialRef.current.opacity = THREE.MathUtils.lerp(
        materialRef.current.opacity, opacity, 0.08
      );
    }
  });
}

function RealPhotoCard({ url, orbit, onClick }) {
  const meshRef = useRef();
  const materialRef = useRef();
  const [hovered, setHovered] = useState(false);
  const texture = useTexture(url);
  useOrbitalPosition(orbit, meshRef, materialRef);

  return (
    <mesh
      ref={meshRef}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.35 : 1}
    >
      <planeGeometry args={[1.6, 1.15]} />
      <meshStandardMaterial
        ref={materialRef}
        map={texture}
        side={THREE.DoubleSide}
        transparent
        opacity={1}
      />
    </mesh>
  );
}

function ColorCard({ color, orbit, index, onClick }) {
  const meshRef = useRef();
  const materialRef = useRef();
  const [hovered, setHovered] = useState(false);
  const threeColor = useMemo(() => new THREE.Color(color), [color]);
  useOrbitalPosition(orbit, meshRef, materialRef);

  return (
    <mesh
      ref={meshRef}
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      onPointerOver={() => { setHovered(true); document.body.style.cursor = 'pointer'; }}
      onPointerOut={() => { setHovered(false); document.body.style.cursor = 'default'; }}
      scale={hovered ? 1.35 : 1}
    >
      <planeGeometry args={[1.6, 1.15]} />
      <meshStandardMaterial
        ref={materialRef}
        color={threeColor}
        emissive={threeColor}
        emissiveIntensity={0.4}
        side={THREE.DoubleSide}
        transparent
        opacity={1}
      />
    </mesh>
  );
}

function PhotoCard({ photo, orbit, index, onClick }) {
  const isColor = photo.startsWith('__color__');
  if (isColor) {
    return <ColorCard color={photo.replace('__color__', '')} orbit={orbit} index={index} onClick={onClick} />;
  }
  return <RealPhotoCard url={photo} orbit={orbit} onClick={onClick} />;
}

export default function PhotoStars({ photos, onPhotoClick }) {
  const orbitParams = useMemo(() => buildOrbitParams(photos.length), [photos.length]);

  return (
    <group>
      {photos.map((photo, i) => (
        <PhotoCard
          key={i}
          photo={photo}
          orbit={orbitParams[i]}
          index={i}
          onClick={() => onPhotoClick(photo, i)}
        />
      ))}
    </group>
  );
}
